// Validation Sandwich - PRE Validate (SEC02) + Regex Whitelist (SEC04)
const input = $input.first()?.json.body || $input.first()?.json || {};
const rawQuery = input.query !== undefined ? String(input.query).trim() : null;
const rawProviderId = input.provider_id !== undefined ? Number(input.provider_id) : null;
const rawLimit = input.limit !== undefined ? Number(input.limit) : 5;
const rawThreshold = input.similarity_threshold !== undefined ? Number(input.similarity_threshold) : 0.2;

const queryRegex = /^[\w\s\-'".,?!():;$\/@&%+=*#\n\r\u00C0-\u017F¿¡]{2,500}$/u;

if (!rawQuery || !queryRegex.test(rawQuery)) throw new Error('VALIDATION_ERROR: query required (min 2 chars, valid chars only)');
if (!rawProviderId || rawProviderId <= 0 || !Number.isInteger(rawProviderId)) throw new Error('VALIDATION_ERROR: provider_id must be positive integer');
if (rawLimit < 1 || rawLimit > 20 || !Number.isInteger(rawLimit)) throw new Error('VALIDATION_ERROR: limit must be integer between 1 and 20');
if (rawThreshold < 0 || rawThreshold > 1 || isNaN(rawThreshold)) throw new Error('VALIDATION_ERROR: similarity_threshold must be number between 0 and 1');

return [{ json: { success: true, error_code: null, error_message: null, query: rawQuery, provider_id: rawProviderId, limit: Math.min(rawLimit, 20), threshold: rawThreshold, _meta: { source: 'RAG_02_Document_Retrieval', timestamp: new Date().toISOString(), version: '1.4.3' } } }];

// Post-Validate Embedding (SEC02)
const response = $input.first()?.json;
if (!response?.data?.[0]?.embedding || response.data[0].embedding.length !== 1536) throw new Error('EMBEDDING_ERROR: OpenAI returned invalid embedding');
const embedding = response.data[0].embedding;
const validatedData = $('Validate & Normalize').first()?.json;
return [{ json: { ...validatedData, embedding } }];

// Build Interpolated Query - FIX DEFINITIVO (service_id is integer)
// O03 + P02 + SEC03 + SEC05
const d = $input.first()?.json;

// Defense-in-depth (SEC02)
if (!Array.isArray(d.embedding) || d.embedding.length !== 1536) 
  throw new Error('BUILD_ERROR: invalid embedding');
if (!Number.isInteger(d.provider_id) || d.provider_id <= 0) 
  throw new Error('BUILD_ERROR: invalid provider_id');
if (!Number.isInteger(d.limit) || d.limit < 1 || d.limit > 20) 
  throw new Error('BUILD_ERROR: invalid limit');
if (typeof d.threshold !== 'number' || d.threshold < 0 || d.threshold > 1) 
  throw new Error('BUILD_ERROR: invalid threshold');

const safeQuery = d.query
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, 500);

const vectorStr = '[' + d.embedding.join(',') + ']';

const query = `
SELECT json_build_object(
  'success', true,
  'data', json_build_object(
    'query', '${safeQuery}'::text,
    'documents', COALESCE(
      (SELECT json_agg(r)
       FROM hybrid_search_rag_documents(
         '${vectorStr}'::vector(1536),
         ${d.provider_id}::integer,
         '${safeQuery}'::text,
         NULL::integer,
         ${d.limit}::integer,
         ${d.threshold}::double precision
       ) r
      ),
      '[]'::json
    )
  ),
  '_meta', json_build_object(
    'source', 'RAG_02_Document_Retrieval',
    'timestamp', now()::text,
    'workflow_id', 'RAG_02',
    'version', '1.4.2'
  )
) AS response
`.trim();

return [{ json: { query, query_text: d.query, provider_id: d.provider_id } }];

// Post-Validate Search (SEC02)
const rows = $input.all();
if (!rows?.[0]?.json?.response) throw new Error('DATABASE_ERROR: No valid response from Postgres');
const response = rows[0].json.response;
if (!Array.isArray(response.data?.documents)) throw new Error('DATABASE_ERROR: documents is not array');
return [{ json: { response } }];

// Format Success Response
const raw = $input.first()?.json?.response || {};
const validatedData = $('Validate & Normalize').first()?.json || {};
const documents = raw.data?.documents || [];
return [{ json: { success: true, error_code: null, error_message: null, data: { query: validatedData.query, documents, document_count: documents.length }, _meta: { source: 'RAG_02_Document_Retrieval', timestamp: new Date().toISOString(), workflow_id: 'RAG_02', version: '1.4.0' } } }];

// Central Error Handler (SEC02)
const input = $input.first()?.json || {};
let errorCode = input.error_code || 'GENERAL_ERROR';
let errorMessage = input.error_message || input.message || input.error?.message || 'Unknown error';
if (!input.error_code && errorMessage.includes(':')) {
  const parts = errorMessage.split(':', 2);
  const known = ['VALIDATION_ERROR','EMBEDDING_ERROR','DATABASE_ERROR','BUILD_ERROR'];
  if (known.includes(parts[0].trim())) { errorCode = parts[0].trim(); errorMessage = parts[1].trim(); }
}
return [{ json: { success: false, error_code: errorCode, error_message: errorMessage, data: null, _meta: { source: 'RAG_02_Document_Retrieval', timestamp: new Date().toISOString(), workflow_id: 'RAG_02', version: '1.4.0' } } }];

// Format Validation Error → Central
const msg = $input.first()?.json?.message || $input.first()?.json?.error?.message || 'Input validation failed';
return [{ json: { error_code: 'VALIDATION_ERROR', error_message: msg } }];

// Format Embedding Error → Central
const msg = $input.first()?.json?.message || $input.first()?.json?.error?.message || 'Failed to generate embedding';
return [{ json: { error_code: 'EMBEDDING_ERROR', error_message: msg } }];

// Format Database Error → Central
const msg = $input.first()?.json?.message || $input.first()?.json?.error?.message || 'Failed to search documents';
return [{ json: { error_code: 'DATABASE_ERROR', error_message: msg } }];

// 📤 STANDARD CONTRACT OUTPUT (O02) - NODO FINAL OBLIGATORIO
const result = $input.first()?.json || {};
return [{ json: { success: result.success !== false, error_code: result.success === false ? (result.error_code || 'UNKNOWN_ERROR') : null, error_message: result.success === false ? (result.error_message || 'An error occurred') : null, data: result.data || null, _meta: { source: 'RAG_02_DOCUMENT_RETRIEVAL', workflow_id: 'RAG_02', timestamp: new Date().toISOString(), version: '1.4.0' } } }];

